//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Theme fonts: rFonts theme attrs and theme->font-table->actual-name
//! resolution".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from ECMA-376 /
//! ISO 29500 / MS-OI29500 for the `rFonts` theme-font slots (`asciiTheme`,
//! `hAnsiTheme`, `eastAsiaTheme`, `cstheme`), the `ST_Theme` token enumeration,
//! and the `hint`/`cs`/`rtl` font-slot routing rules.
//!
//! A FAIL here encodes a REAL Word-compliance gap in the stemma engine — it is
//! NOT to be "fixed" by weakening the assertion. The assertion message carries
//! the rule text + spec §refs so the failure is self-explanatory.
//!
//! METHODOLOGY NOTE (consumption vs save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `reserialize()` of an unedited doc reflects stemma's
//! verbatim-preservation contract, not Word's render-time normalization.
//! `xmlContains`/`xmlOmits` here are used ONLY for tokens stemma's serializer
//! actively re-emits verbatim (theme tokens survive the passthrough) or for
//! structural validity; consumption semantics ("font slot selection") are
//! tested on the READ side via `read_accepted()/read_rejected().to_text()`.

use std::io::Read;

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a minimal valid `.docx`. `body_xml` is the inner content of
/// `<w:body>…</w:body>` (paragraphs, sectPr, …). `extra_parts` are additional
/// package parts as `(part_path, xml)` — e.g. `("word/styles.xml", …)`; each
/// gets a matching `[Content_Types].xml` Override and a document rels entry.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type override per known extra part.
    let mut overrides = String::new();
    let mut doc_rels_entries = String::new();
    for (idx, (path, _xml)) in extra_parts.iter().enumerate() {
        let part_name = if path.starts_with('/') {
            path.to_string()
        } else {
            format!("/{path}")
        };
        let (content_type, rel_type) = if path.ends_with("styles.xml") {
            (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
            )
        } else if path.ends_with("numbering.xml") {
            (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
            )
        } else if path.ends_with("theme1.xml") {
            (
                "application/vnd.openxmlformats-officedocument.theme+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/theme",
            )
        } else {
            (
                "application/xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/customXml",
            )
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_name}" ContentType="{content_type}"/>"#
        ));
        // Relationship target is relative to word/ (the document part lives in word/).
        let target = path.strip_prefix("word/").unwrap_or(path);
        doc_rels_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{idx}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return the `word/document.xml` text.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse → serialize (default ExportOptions) → return the re-emitted
/// `word/document.xml`. Valid only for asserting on markup the serializer
/// actively re-emits (theme tokens are preserved verbatim through passthrough)
/// or for structural validity.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Assert `stemma::api::validate` reports no errors (opens clean in Word).
fn assert_opens_clean(bytes: &[u8], rule_refs: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule_refs} — expected the package to open clean (validate ok, no issues), got ok={} issues={:?}",
        report.ok,
        report.issues
    );
}

