#[test]
fn ascii_axis_theme_tokens_major_minor_ascii_legal_and_preserved() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:asciiTheme="majorAscii"/></w:rPr><w:t>Major ASCII theme run</w:t></w:r></w:p><w:p><w:r><w:rPr><w:rFonts w:asciiTheme="minorAscii"/></w:rPr><w:t>Minor ASCII theme run</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "majorAscii/minorAscii are enumerated ST_Theme values (ISO 29500-1 §17.18.96; ECMA-376 §17.3.2.26) — both rFonts schema-valid, Word opens without repair",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:asciiTheme="majorAscii""#),
        "asciiTheme token must survive roundtrip verbatim, not flattened to a concrete face (ISO 29500-1 §17.18.96; ECMA-376 §17.3.2.26) — expected XML to contain w:asciiTheme=\"majorAscii\"; got: {xml}"
    );
    assert!(
        xml.contains(r#"w:asciiTheme="minorAscii""#),
        "minorAscii token must likewise be preserved as a token on roundtrip per the central-theme-reference contract (ISO 29500-1 §17.18.96) — expected XML to contain w:asciiTheme=\"minorAscii\"; got: {xml}"
    );
}

#[test]
fn cstheme_off_axis_major_eastasia_lowercase_name_preserved_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:cstheme="majorEastAsia"/><w:cs/></w:rPr><w:t>complex script theme</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "cstheme is typed ST_Theme and majorEastAsia is an enumerated ST_Theme value (ECMA-376 §17.3.2.26; ISO 29500-1 §17.18.96) — run schema-valid, Word opens without repair",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:cstheme="majorEastAsia""#),
        "CT_Fonts spells the attribute lowercase 'cstheme' and the token is preserved verbatim (ECMA-376 §17.3.2.26; wml.xsd CT_Fonts) — expected XML to contain w:cstheme=\"majorEastAsia\"; got: {xml}"
    );
    assert!(
        !xml.contains("w:csTheme="),
        "CT_Fonts spells the attribute lowercase 'cstheme'; camelCase 'csTheme' is invalid markup the serializer must never produce (ECMA-376 §17.3.2.26; wml.xsd CT_Fonts) — expected XML to omit w:csTheme=; got: {xml}"
    );
}

#[test]
fn cs_forces_cstheme_slot_for_all_chars_text_identity_no_revision() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:cstheme="minorBidi"/><w:cs/></w:rPr><w:t>English 中文</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "English 中文".trim(),
        "cstheme+cs only selects the font slot (MS-OI29500 §2.1.88; ECMA-376 §17.3.2.26); it is not a revision, so accept-all yields the original mixed-script text unchanged — got {accepted:?}"
    );

    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "English 中文".trim(),
        "no tracked change present; the cs font-slot rule is consumption-only and cannot alter run content (MS-OI29500 §2.1.88; ISO 29500-1 §17.3.2.30) — got {rejected:?}"
    );

    assert_opens_clean(
        &b,
        "minorBidi is a valid ST_Theme value and cs is valid run markup (ECMA-376 §17.3.2.26) — package opens without repair",
    );
}

#[test]
fn coexisting_ascii_and_asciitheme_legal_text_identity() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Arial" w:asciiTheme="minorHAnsi"/></w:rPr><w:t>both ascii and asciiTheme</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    assert_opens_clean(
        &b,
        "both ascii and asciiTheme on one rFonts is legal markup Word consumes without rewriting (ECMA-376 §17.3.2.26; MS-OI29500 §2.1.88) — package opens without repair",
    );

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "both ascii and asciiTheme".trim(),
        "the ascii/asciiTheme arbitration is font-resolution only (ECMA-376 §17.3.2.26); not a revision, so accept-all leaves run text unchanged — got {accepted:?}"
    );

    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "both ascii and asciiTheme".trim(),
        "no tracked change present, so reject-all reproduces the original run text verbatim (MS-OI29500 §2.1.88) — got {rejected:?}"
    );
}

