#[test]
fn rtl_alone_triggers_cstheme_font_slot_text_preserved() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:cstheme="minorBidi"/><w:rtl/></w:rPr><w:t>right to left complex run</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    assert_opens_clean(
        &b,
        "w:rtl plus a cstheme=minorBidi token is valid CT_Fonts + EG_RPrBase markup (MS-OI29500 §2.1.88; ISO 29500-1 §17.3.2.26) — Word opens without repair",
    );

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "right to left complex run".trim(),
        "rtl triggers the cstheme font slot for layout only (MS-OI29500 §2.1.88); with no tracked change present, accepted text must equal the source run text — got {accepted:?}"
    );

    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "right to left complex run".trim(),
        "font slot selection is not a revision, so reject-all reproduces the same text as accept (MS-OI29500 §2.1.88; ISO 29500-1 §17.3.2.30) — got {rejected:?}"
    );
}

