#[test]
fn theme_rfonts_run_inside_ins_accept_keeps_reject_drops() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:asciiTheme="minorHAnsi"/></w:rPr><w:t xml:space="preserve">Base </w:t></w:r><w:ins w:id="5" w:author="A" w:date="2024-01-01T00:00:00Z"><w:r><w:rPr><w:rFonts w:asciiTheme="majorHAnsi" w:cstheme="minorBidi"/></w:rPr><w:t>added</w:t></w:r></w:ins></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "Base added".trim(),
        "accepting the insertion keeps the inserted run's text; theme-slot attrs are font properties and do not alter resolved content (MS-OI29500 §2.1.88; ECMA-376 §17.3.2.26; ISO 29500-1 §17.13.5.16) — got {accepted:?}"
    );

    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "Base".trim(),
        "rejecting the insertion removes exactly the w:ins run text; theme attrs must not cause base text to be added/dropped (MS-OI29500 §2.1.88; ISO 29500-1 §17.13.5.16) — got {rejected:?}"
    );

    assert_opens_clean(
        &b,
        "theme attrs on a run inside w:ins are schema-valid CT_Fonts on a valid CT_RunTrackChange (ECMA-376 §17.3.2.26; ISO 29500-1 §17.13.5.16) — Word opens without repair",
    );
}

#[test]
fn within_element_multislot_coexistence_in_del_reject_restores_text() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:asciiTheme="minorHAnsi"/></w:rPr><w:t xml:space="preserve">Keep </w:t></w:r><w:del w:id="9" w:author="X" w:date="2024-01-01T00:00:00Z"><w:r><w:rPr><w:rFonts w:ascii="Arial" w:asciiTheme="minorHAnsi" w:eastAsia="MS Mincho" w:eastAsiaTheme="minorEastAsia"/></w:rPr><w:delText>gone</w:delText></w:r></w:del></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "Keep gone".trim(),
        "rejecting the deletion restores the deleted run text verbatim; coexisting explicit+theme slots are font selectors and must not alter restored content (MS-OI29500 §2.1.88; ECMA-376 §17.3.2.26; ISO 29500-1 §17.13.5.14) — got {rejected:?}"
    );

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "Keep".trim(),
        "accepting the deletion removes exactly the w:delText; the multi-slot rFonts must not retain/duplicate deleted text (MS-OI29500 §2.1.88; ISO 29500-1 §17.13.5.14) — got {accepted:?}"
    );

    assert_opens_clean(
        &b,
        "ascii+asciiTheme+eastAsia+eastAsiaTheme on one rFonts is legal CT_Fonts (the ignore is per-element consumption, not a schema constraint) (MS-OI29500 §2.1.88; ECMA-376 §17.3.2.26) — Word opens without repair",
    );
}

#[test]
fn theme_eastasia_hint_run_in_del_reject_restores_text() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:asciiTheme="minorHAnsi"/></w:rPr><w:t xml:space="preserve">Keep </w:t></w:r><w:del w:id="6" w:author="A" w:date="2024-01-01T00:00:00Z"><w:r><w:rPr><w:rFonts w:eastAsiaTheme="minorEastAsia" w:hint="eastAsia"/></w:rPr><w:delText>gone</w:delText></w:r></w:del></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let doc = Document::parse(&b).expect("parse");

    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "Keep gone".trim(),
        "rejecting the deletion restores the deleted run text; eastAsiaTheme + hint='eastAsia' are EA-slot font selectors and must not change restored content (MS-OI29500 §2.1.88; ISO 29500-1 §17.18.41) — got {rejected:?}"
    );

    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "Keep".trim(),
        "accepting the deletion removes the w:delText exactly; EA-slot theme/hint arbitration must not retain deleted text (ISO 29500-1 §17.13.5.14) — got {accepted:?}"
    );

    assert_opens_clean(
        &b,
        "eastAsiaTheme + hint='eastAsia' on a run inside w:del is schema-valid CT_Fonts on a CT_RunTrackChange (ISO 29500-1 §17.18.41; MS-OI29500 §2.1.88) — Word opens without repair",
    );
}

